#ifndef CALIBRATOR_H
#define CALIBRATOR_H
#include <Arduino.h>

class Calibrator {
public:
    Calibrator(float offset = 0.0f, float scale = 1.0f);
    float apply(float raw);
    void setCalibration(float offset, float scale);
private:
    float _offset, _scale;
};

#endif

firmware_template.source:
#include "calibrator.h"

Calibrator::Calibrator(float offset, float scale)
    : _offset(offset), _scale(scale) {}

float Calibrator::apply(float raw) {
    return (raw + _offset) * _scale;
}

void Calibrator::setCalibration(float offset, float scale) {
    _offset = offset; _scale = scale;
}
